export interface FrameworkLevel {
  t: string; // title
  d: string; // description
  q: [string, string][]; // questions: [text, evidenceHint]
}

export interface Framework {
  name: string;
  color: string;
  short: string;
  levels: FrameworkLevel[];
}

export interface Stage {
  key: string;
  label: string;
  short: string;
}

export const STAGES: Stage[] = [
  { key: "idea",         label: "Idea",         short: "Opportunity and value hypothesis identified; no prototype yet." },
  { key: "poc",          label: "POC",          short: "Proof-of-concept demonstrated in lab or simulation." },
  { key: "mvp",          label: "MVP",          short: "Early customer validation; MVP live; pre-revenue or first signs." },
  { key: "earlyRevenue", label: "Early Rev.",   short: "Paying pilots / recurring revenue; product-market fit signals." },
  { key: "growth",       label: "Growth",       short: "Scalable GTM, operations and hiring." },
  { key: "scale",        label: "Scale",        short: "Category leadership; large-scale, durable impact." }
];

